// Normalise Google Ads response â†’ campaigns_daily schema
const rows = [];
for (const item of $input.all()) {
  const r = item.json;
  const campaign  = r.campaign || {};
  const metrics   = r.metrics  || {};
  rows.push({ json: {
    date:          $('Trigger').first().json.yesterday,
    channel:       'google_ads',
    campaign_id:   String(campaign.id || ''),
    campaign_name: campaign.name || '',
    impressions:   Number(metrics.impressions || 0),
    clicks:        Number(metrics.clicks || 0),
    spend:         Number(metrics.costMicros || 0) / 1_000_000,
    conversions:   Number(metrics.conversions || 0),
  }});
}
return rows;

const rows = [];
for (const item of $input.all()) {
  const d = item.json;
  rows.push({ json: {
    date:          d.date_start || $('Trigger').first().json.yesterday,
    channel:       'meta',
    campaign_id:   String(d.campaign_id || ''),
    campaign_name: d.campaign_name || '',
    impressions:   Number(d.impressions || 0),
    clicks:        Number(d.clicks || 0),
    spend:         Number(d.spend || 0),
    conversions:   (d.actions||[]).filter(a=>a.action_type==='lead').reduce((s,a)=>s+Number(a.value||0),0),
  }});
}
return rows;

const rows = [];
for (const item of $input.all()) {
  const s = item.json;
  const stats = (s.timeseries_stats || [s])[0] || {};
  rows.push({ json: {
    date:          $('Trigger').first().json.yesterday,
    channel:       'snapchat',
    campaign_id:   String(s.id || s.campaign_id || ''),
    campaign_name: s.name || s.campaign_name || '',
    impressions:   Number(stats.impressions || 0),
    clicks:        Number(stats.swipes || 0),
    spend:         Number(stats.spend || 0) / 1_000_000,
    conversions:   Number(stats.conversion_sign_ups || 0),
  }});
}
return rows;

const rows = [];
for (const item of $input.all()) {
  const d = item.json;
  const metrics = d.metrics || {};
  rows.push({ json: {
    date:          d.dimensions?.stat_time_day?.slice(0,10) || $('Trigger').first().json.yesterday,
    channel:       'tiktok',
    campaign_id:   String(d.dimensions?.campaign_id || ''),
    campaign_name: d.dimensions?.campaign_name || '',
    impressions:   Number(metrics.impressions || 0),
    clicks:        Number(metrics.clicks || 0),
    spend:         Number(metrics.spend || 0),
    conversions:   Number(metrics.complete_payment || metrics.onsite_confirm_cnt || 0),
  }});
}
return rows;

const rows = [];
for (const item of $input.all()) {
  const d = item.json;
  rows.push({ json: {
    date:          $('Trigger').first().json.yesterday,
    channel:       'linkedin',
    campaign_id:   String(d.pivotValues?.[0]?.replace('urn:li:sponsoredCampaign:','') || ''),
    campaign_name: d.campaign?.name || '',
    impressions:   Number(d.impressions || 0),
    clicks:        Number(d.clicks || 0),
    spend:         Number(d.costInUsd || 0),
    conversions:   Number(d.leadGenerationMailContactInfoShares || d.viralLeadGenerationMailContactInfoShares || 0),
  }});
}
return rows;

// Group mapped rows by channel+campaign_id+date, sum metrics
const map = new Map();
for (const item of $input.all()) {
  const r = item.json;
  const key = `${r.date}|${r.channel}|${r.campaign_id}`;
  if (!map.has(key)) map.set(key, {...r, impressions:0, clicks:0, spend:0, conversions:0});
  const cur = map.get(key);
  cur.impressions  += r.impressions  || 0;
  cur.clicks       += r.clicks       || 0;
  cur.spend        += r.spend        || 0;
  cur.conversions  += r.conversions  || 0;
}
return [...map.values()].map(r => ({ json: r }));

const rows  = $input.all().map(i => i.json);
const today = $('Trigger').first().json.yesterday;
const summary = rows.reduce((acc, r) => {
  acc[r.channel] = acc[r.channel] || { spend:0, impressions:0, conversions:0, rows:0 };
  acc[r.channel].spend       += r.spend || 0;
  acc[r.channel].impressions += r.impressions || 0;
  acc[r.channel].conversions += r.conversions || 0;
  acc[r.channel].rows++;
  return acc;
}, {});

const report = Object.entries(summary).map(([ch, s]) =>
  `${ch}: ${s.rows} rows, $${s.spend.toFixed(2)} spend, ${s.impressions} impressions`
).join('\n');

return [{ json: {
  system: `You are a data quality guard for a paid media system. Flag corrupt, zero-spend, or suspiciously low data.`,
  messages: [{
    role: 'user',
    content: `Date: ${today}\nData summary:\n${report}\n\nValidate this data. Use the report_guard tool.`
  }],
  tools: [{
    name: 'report_guard',
    description: 'Report data quality verdict',
    input_schema: {
      type: 'object',
      properties: {
        should_load: { type: 'boolean', description: 'true if data looks valid' },
        reason:      { type: 'string',  description: 'One sentence explanation' },
        flags:       { type: 'array', items: { type: 'string' }, description: 'channels with issues' }
      },
      required: ['should_load','reason']
    }
  }],
  rows,
}}];

const resp = $input.first().json;
const block = (resp.content||[]).find(b => b.type==='tool_use' && b.name==='report_guard');
if (!block) return [{ json: { should_load: false, reason: 'guard_no_tool_use', flags:[] }}];
return [{ json: block.input }];

// Compare BQ lead counts to HubSpot API response
const bqRows  = $('Query BQ Recon').all().map(i=>i.json);
const hsTotal = $('Query HS Recon').first().json?.total || 0;
const bqTotal = bqRows.reduce((s,r)=>s+(r.bq_leads||0), 0);

const delta = bqTotal > 0 ? Math.abs(bqTotal - hsTotal) / bqTotal : 0;
const ok    = delta <= 0.02; // 2% tolerance

return [{ json: {
  recon_ok:      ok,
  bq_total:      bqTotal,
  hs_total:      hsTotal,
  delta_pct:     Math.round(delta*100*10)/10,
  channel_breakdown: bqRows,
  alert_msg: ok ? null :
    `BQâ†”HubSpot gap: BQ=${bqTotal} HS=${hsTotal} (${Math.round(delta*100)}% delta) â€” exceeds 2% threshold`
}}];

const yesterday = $('Trigger').first().json.yesterday;
const proj = $vars.BQ_PROJECT;
const ds   = $vars.BQ_DATASET;
const results = [];

// â”€â”€ AD CHANNELS â†’ campaigns_daily â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
const adMaps = [
  'Map Â· Google Ads',
  'Map Â· Meta',
  'Map Â· Snapchat',
  'Map Â· TikTok',
  'Map Â· LinkedIn',
  'Map Â· Microsoft Ads',
];

for (const mapNode of adMaps) {
  const rows = $(mapNode).all().map(i => i.json);
  if (!rows.length) continue;
  const vals = rows.map(r => `STRUCT(
  DATE('${(r.date||yesterday).replace(/'/g,"''")}') AS date,
  '${(r.channel||'').replace(/'/g,"''")}' AS channel,
  '${String(r.campaign_id||'').replace(/'/g,"''")}' AS campaign_id,
  '${String(r.campaign_name||'').replace(/'/g,"''")}' AS campaign_name,
  ${r.impressions||0} AS impressions,
  ${r.clicks||0} AS clicks,
  ${Number(r.spend||0).toFixed(6)} AS spend,
  ${r.conversions||0} AS conversions
)`).join(',\n');
  const sql = `MERGE \`${proj}.${ds}.campaigns_daily\` AS T
USING (SELECT * FROM UNNEST([${vals}])) AS S
ON T.date=S.date AND T.channel=S.channel AND T.campaign_id=S.campaign_id
WHEN MATCHED THEN UPDATE SET
  campaign_name=S.campaign_name, impressions=S.impressions,
  clicks=S.clicks, spend=S.spend, conversions=S.conversions,
  updated_at=CURRENT_TIMESTAMP()
WHEN NOT MATCHED THEN INSERT
  (date,channel,campaign_id,campaign_name,impressions,clicks,spend,conversions,created_at,updated_at)
VALUES(S.date,S.channel,S.campaign_id,S.campaign_name,S.impressions,S.clicks,S.spend,S.conversions,CURRENT_TIMESTAMP(),CURRENT_TIMESTAMP())`;
  results.push({ json: { channel: rows[0]?.channel || mapNode, sql } });
}


return results;

